    pub const fn blade_of_the_ruined_king_ranged_min(ctx: &Ctx) -> f32 {
        ctx.attack_damage * ctx.physical_multiplier
            + 0.06 * ctx.enemy_current_health * ctx.physical_multiplier
    }
